import{_ as e,c as r,o as t,ae as p}from"./chunks/framework.BvcDoAct.js";const l=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/Management2/PART2/1.md","filePath":"zh-cn/Management2/PART2/1.md"}'),E={name:"zh-cn/Management2/PART2/1.md"};function T(o,a,i,n,S,R){return t(),r("div",null,[...a[0]||(a[0]=[p('<p>►2022/11</p><h2 id="承接-be-first-的新团体-mazzel-关于-迷宫-与-热情-的命名寓意" tabindex="-1">承接 BE:FIRST 的新团体 MAZZEL：关于“迷宫”与“热情”的命名寓意 <a class="header-anchor" href="#承接-be-first-的新团体-mazzel-关于-迷宫-与-热情-的命名寓意" aria-label="Permalink to &quot;承接 BE:FIRST 的新团体 MAZZEL：关于“迷宫”与“热情”的命名寓意&quot;">​</a></h2><p>#新项目 #Mx2 #MAZZEL #不安 #烦恼 #觉悟 #幸福 #自有媒体</p><h3 id="在人生之中-不安与烦恼始终如影随形。每个人都渴望获得幸福-而娱乐本应成为支撑这种情感、并给予启发的存在。" tabindex="-1">“在人生之中，不安与烦恼始终如影随形。每个人都渴望获得幸福，而娱乐本应成为支撑这种情感、并给予启发的存在。” <a class="header-anchor" href="#在人生之中-不安与烦恼始终如影随形。每个人都渴望获得幸福-而娱乐本应成为支撑这种情感、并给予启发的存在。" aria-label="Permalink to &quot;“在人生之中，不安与烦恼始终如影随形。每个人都渴望获得幸福，而娱乐本应成为支撑这种情感、并给予启发的存在。”&quot;">​</a></h3><p>2022年11月22日，BMSG在记者发布会上宣布，与环球音乐共同成立联合厂牌“BE-U”，并突然公开了继 BE:FIRST 之后推出的第二支舞蹈&amp;歌唱组合——“MAZZEL”。这是一个由8人组成的男团。那么，在这个时间点将他们推向市场的用意是什么？他们又会成为一个怎样的团体？</p><p>“MAZZEL”这个名字本身包含“福音”“幸运”之意的“mazel”，同时也是“Maze”（迷宫）与“Zeal”（热情）的结合。人生就像他们在出道前所经历的那样，是一座充满迷惘与烦恼的“迷宫”。但无论如何，出口始终存在。这个名字所寄托的，是一个朝着“出口”燃烧热情、抓住“幸福”，并将其传递给他人的团体愿景。</p><p>在人生中，不安与烦恼是无法避免的。但每个人都渴望幸福，而娱乐原本就应该成为帮助人们理解并引导这种情感的存在。这种作为“人”的普遍性，正是“MAZZEL”的核心主题。</p><h3 id="选择不同道路的-ran-与-reiko" tabindex="-1">选择不同道路的 RAN 与 REIKO <a class="header-anchor" href="#选择不同道路的-ran-与-reiko" aria-label="Permalink to &quot;选择不同道路的 RAN 与 REIKO&quot;">​</a></h3><p>参加了诞生 BE:FIRST 的选秀“THE FIRST”，并在之后成为练习生的 RAN 与 REIKO，此后持续接受包括歌唱与舞蹈在内的多方面训练。同时，他们也一直被要求不断思考：“自己真正想做什么 / 想成为什么样的人”。最终，REIKO选择了一条不同于“MAZZEL”的道路。</p><p>两人从一开始就并非内定为新团体成员，而是与其他候选者站在同一起跑线上。尽管如此，一方面是逐渐萌生了想作为舞蹈&amp;歌唱组合成员活动的意愿，却在过程中屡屡受挫的RAN；另一方面，是在作为音乐人的自我意识觉醒后不断尝试各种可能，最终选择走向“MAZZEL”之外道路的REIKO——这两个人的故事，正是此次项目的起点。</p><p>回到“THE FIRST”时期，现在 BE:FIRST 的成员虽然各自时机不同，但大多已经下定决心，将“作为唱跳组合的一员活动”作为自己的人生方向。但当时的RAN与REIKO，则通过他们的表演，能够明显感受到仍然存在某种程度的迷惘与犹豫。</p><p>换句话说，两人各自都有需要面对的课题。对于RAN而言，不仅要坚定作为唱跳组合成员的决心，还需要通过表演进一步明确“自己作为艺人想要成为什么样的存在”；而REIKO则是在完全没有歌舞经验的情况下参加“THE FIRST”，通过选秀才真正接触音乐，因此必须持续思考“自己真正该做的事、真正想做的事到底是什么”。</p><p>因此，在“THE FIRST”之后，我们一直将关注点放在他们的成长，以及他们的意识与方向如何变化上，也在台面之下为他们进行了各种尝试与探索。</p><p>至于REIKO最终是如何决定走向“MAZZEL”之外的道路的，这部分过程，可以通过2023年1月起在YouTube频道上线的选秀纪录节目《MISSIONx2》来了解。</p><h3 id="新团体-mazzel-的命名中-也能感受到对sky-hi而言的-迷宫-这一意象" tabindex="-1">新团体“MAZZEL”的命名中，也能感受到对SKY-HI而言的“迷宫”这一意象 <a class="header-anchor" href="#新团体-mazzel-的命名中-也能感受到对sky-hi而言的-迷宫-这一意象" aria-label="Permalink to &quot;新团体“MAZZEL”的命名中，也能感受到对SKY-HI而言的“迷宫”这一意象&quot;">​</a></h3><p>只要活着，每个人都会拥有属于自己的故事。因此，这个项目同样也会成为参与者各自寻找“走出迷宫之路”的一个起点。作为BMSG，我们并不满足于那种“什么都不去思考、放弃思考与行动，并把这种状态当作‘幸福’”的观念，而是希望那些真正渴望追求并获得“本质上的幸福”的人聚集在一起。因此，他们将如何找到那条道路，这个过程本身就是我们非常珍视的部分。</p><p>而所谓的“迷宫”，对我来说也是一样的存在。在过去这一年左右，“MAZZEL”的组建项目始终伴随着各种烦恼：什么时候推出、推出什么、该如何推进等等，需要思考的问题非常多。其中最关键的一点，是必须去做与作为强烈成功经验的BE:FIRST完全不同的事情。对我个人来说，这正是走出这座“迷宫”的出口。</p><h3 id="挑战自有媒体的运用" tabindex="-1">挑战自有媒体的运用 <a class="header-anchor" href="#挑战自有媒体的运用" aria-label="Permalink to &quot;挑战自有媒体的运用&quot;">​</a></h3><p>这次我们刻意选择在BMSG的YouTube频道上进行发布。在项目发布记者会上，我也提到过“本来就想在YouTube上做”。</p><p>原因有很多，但简单来说，引入更多与“渠道（观众触点、媒体平台）”相关的外部合作方，就像往咖啡里加入牛奶一样——虽然我们希望确保咖啡本身的味道，但多少会变成另一种风味。被更多人知道当然很重要，从更广义的大众传播角度来看，增加渠道也是必要的，但与此同时，想要守住原本的“味道”就会变得非常困难。</p><p>而如果渠道只有BMSG本身，那么在核心团队主导下，无论做什么，最终呈现的都会是最纯粹的BMSG。创业初期做“THE FIRST”的时候，是因为我可以100%投入其中，所以才能做出令自己满意的成果。但这一次，我需要一边推进以BE:FIRST为核心的多项事务，一边进行“MISSIONx2”，如果再去扩展渠道，很可能会让BMSG真正想做、应该做的事情在过程中被稀释，这是我非常担心的风险。</p><p>另一方面，也正因为这两年已经逐渐形成了属于BMSG的组织风格，我认为可以、也希望通过自有媒体来完成这件事。从“想做”的角度来说，未来拥有以自有平台为基础、作为自有媒体所具备的传播能力，将是绝对必要的。就像（以美国为据点、向世界传播亚洲文化的厂牌兼媒体）88rising那样，我强烈感受到这种必要性。比起短期的成功或失败，在这个阶段进行一次这样的尝试，本身就是必须的。</p><h3 id="与-be-first-完全相反的呈现方式" tabindex="-1">与 BE:FIRST 完全相反的呈现方式 <a class="header-anchor" href="#与-be-first-完全相反的呈现方式" aria-label="Permalink to &quot;与 BE:FIRST 完全相反的呈现方式&quot;">​</a></h3><p>BE:FIRST当时，是通过几乎实时地展示选秀到成团全过程，让观众逐步产生情感投入与期待，从而在出道前就积累了大量粉丝。而这一次，则是先公布出道成员，再回溯他们成团过程——在时间顺序上完全相反。</p><p>对我来说，这个项目的前提就是：如果不去做与“THE FIRST”和BE:FIRST不同的事情，那就没有意义。BE:FIRST本身就是由那些在既有娱乐体系中无法被充分发挥、难以融入的人聚集而成的。如果反过来把“THE FIRST”的机制或BE:FIRST的成员构成固化为一种“模板”，那就完全本末倒置，也是最危险的事情。所以，这一次必须从头到尾都做到不同。</p><p>而且，“THE FIRST”是一个我全身心投入的项目——甚至在合宿中与参与者同吃同住。那段时间，我脑子里只有“THE FIRST”这一件事。但这一次，公司规模和状况都已经发生变化，不可能再做完全相同的事情。如果只是照搬形式，最后只会变成一个“劣化版本”，甚至注定失败。</p><p>因此，在这次项目中，我从一开始就认为，先呈现“结果（终点）”，再以纪录片形式展开过程，是更合适的方式。成员确定之前的过程也会通过YouTube逐步公开。希望大家能见证他们走出第一座“迷宫”的过程——当你真正看到之后，应该也会理解为什么这种形式是最合适的。从项目本质来说，它的一个核心高潮，其实从第一集就已经开始显现了。</p><h3 id="赋予与-be-first-完全不同的意义" tabindex="-1">赋予与 BE:FIRST 完全不同的意义 <a class="header-anchor" href="#赋予与-be-first-完全不同的意义" aria-label="Permalink to &quot;赋予与 BE:FIRST 完全不同的意义&quot;">​</a></h3><p>“MAZZEL”也是由BMSG与环球音乐共同成立的新厂牌“BE-U”推出的首个项目。在正式上线之前，具体内容还需“敬请期待”，但观众可以对其抱有什么样的期待？</p><p>MAZZEL这个项目，从一开始就处在与BE:FIRST完全不同的条件之下，也理所当然地必须走向完全不同的方向。坦白说，我一直很警惕自己被BE:FIRST的成功经验所牵引。试图去复刻从“THE FIRST”开始的成功，是一件非常危险的事情。</p><p>但与此同时，如果说是顺势承接“THE FIRST”所带来的动能，或者将其中的逻辑进行转化与应用来实现成长，那么我认为在现阶段，我们正处在一个非常好的状态。我也强烈感受到，MAZZEL有可能创造出与BE:FIRST截然不同的意义、价值以及结果。</p>',31)])])}const h=e(E,[["render",T]]);export{l as __pageData,h as default};
